def gen(rng, size):
    depth = 0
    out = []
    n = rng.randint(1, max(1, size))
    for _ in range(n):
        r = rng.random()
        if r < 0.45:
            out.append('(')
            depth += 1
        elif r < 0.8 and depth > 0:
            out.append(')')
            depth -= 1
        else:
            out.append('*')
    return [''.join(out)]

