class Solution:
    def checkValidString(self, s):
        from functools import lru_cache
        n = len(s)
        @lru_cache(maxsize=None)
        def ok(i, bal):
            if bal < 0:
                return False
            if i == n:
                return bal == 0
            c = s[i]
            if c == '(': 
                return ok(i + 1, bal + 1)
            if c == ')':
                return ok(i + 1, bal - 1)
            return ok(i + 1, bal + 1) or ok(i + 1, bal - 1) or ok(i + 1, bal)
        return ok(0, 0)

